-- Change to match your DB if you have other spawns I didn't when I set this up.

SET @CGUID := 9010000;

DELETE FROM `creature` WHERE `guid` BETWEEN @CGUID+0 AND @CGUID+7520;































-- The data has some duplicate spawns, so I added this to clean them up.
DELETE spawn1
FROM creature spawn1
JOIN creature spawn2
  ON spawn1.id = spawn2.id
  AND spawn1.position_x = spawn2.position_x
  AND spawn1.position_y = spawn2.position_y
  AND spawn1.position_z = spawn2.position_z
  AND spawn1.guid > spawn2.guid
WHERE spawn1.guid BETWEEN @CGUID+0 AND @CGUID+7520
  AND spawn2.guid BETWEEN @CGUID+0 AND @CGUID+7520;
  
